import{c as l,S as i,j as a,m as o}from"./chunks/framework.DvQr6YbT.js";const u=JSON.parse('{"title":"故障排查","description":"","frontmatter":{},"headers":[],"relativePath":"zh/troubleshooting/index.md","filePath":"zh/troubleshooting/index.md","lastUpdated":1783065655000}'),n={name:"zh/troubleshooting/index.md"};function s(d,e,t,r,c,p){return i(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="故障排查" tabindex="-1">故障排查 <a class="header-anchor" href="#故障排查" aria-label="Permalink to “故障排查”">​</a></h1><p>当 setup、skills、平台配置或 vault health 看起来不正常时，可以从这里开始。</p><h2 id="dashboard-显示-vault-尚未设置" tabindex="-1">Dashboard 显示 Vault 尚未设置 <a class="header-anchor" href="#dashboard-显示-vault-尚未设置" aria-label="Permalink to “Dashboard 显示 Vault 尚未设置”">​</a></h2><p>Knowlery 会检查 <code>.knowlery/manifest.json</code> 或 <code>KNOWLEDGE.md</code>。</p><p>如果这个 vault 理论上已经初始化：</p><ol><li>确认 <code>.knowlery/manifest.json</code> 或 <code>KNOWLEDGE.md</code> 存在。</li><li>如果 manifest 存在，确认它是合法 JSON。</li><li>重新打开 dashboard。</li><li>如果文件缺失或损坏，重新运行 setup，或在 settings 中使用 maintenance actions。</li></ol><h2 id="无法检测到-node-js" tabindex="-1">无法检测到 Node.js <a class="header-anchor" href="#无法检测到-node-js" aria-label="Permalink to “无法检测到 Node.js”">​</a></h2><p>Node.js 用于 skill registry 浏览和可选 tooling preparation。</p><p>可以尝试：</p><ol><li>从 Node.js 官方网站安装 Node.js。</li><li>重启 Obsidian。</li><li>在 Knowlery settings 中使用 Node.js auto-detect。</li><li>如果 auto-detect 失败，手动填写 Node.js 路径。</li></ol><p>在 macOS 和 Linux 上，GUI apps 有时不会继承 terminal 中的 shell PATH。此时可能需要手动填写路径。</p><h2 id="skill-browser-无法使用" tabindex="-1">Skill Browser 无法使用 <a class="header-anchor" href="#skill-browser-无法使用" aria-label="Permalink to “Skill Browser 无法使用”">​</a></h2><p>Skill browser 依赖 Node.js、npm，以及通过 <code>npx skills</code> 调用的外部 skills CLI。</p><p>检查：</p><ul><li>Node.js 已安装并被检测到。</li><li>npm 可用。</li><li>搜索词不为空。</li><li>网络访问可用。</li><li>外部 skills registry 可访问。</li></ul><p>如果 registry 暂时不可用，built-in skills 和 custom skills 仍然可以使用。</p><h2 id="built-in-skills-缺失" tabindex="-1">Built-In Skills 缺失 <a class="header-anchor" href="#built-in-skills-缺失" aria-label="Permalink to “Built-In Skills 缺失”">​</a></h2><p>打开 <strong>Settings -&gt; Knowlery</strong>，然后在 Diagnostics 里检查 <strong>Skills installed</strong>。</p><p>Built-in skills 预期位于 <code>.agents/skills/&lt;name&gt;/SKILL.md</code>。</p><p>如果有缺失：</p><ol><li>在 test vault 中重新运行 setup，对比预期输出。</li><li>如果 skill 是被禁用的，尝试从 settings 的 Skills 区块重新启用。</li><li>如果安装不完整，可以使用 maintenance actions 重新初始化或修复 vault。</li></ol><h2 id="claude-code-config-缺失" tabindex="-1">Claude Code Config 缺失 <a class="header-anchor" href="#claude-code-config-缺失" aria-label="Permalink to “Claude Code Config 缺失”">​</a></h2><p>对于 Claude Code，Knowlery 预期存在：</p><ul><li><code>.claude/CLAUDE.md</code></li><li><code>.claude/rules/</code></li><li><code>.agents/skills/</code></li></ul><p>可以在 settings 中重新生成 agent config。如果你曾从 OpenCode 切换过来，请确认当前 active platform 是 Claude Code。</p><h2 id="opencode-config-缺失" tabindex="-1">OpenCode Config 缺失 <a class="header-anchor" href="#opencode-config-缺失" aria-label="Permalink to “OpenCode Config 缺失”">​</a></h2><p>对于 OpenCode，Knowlery 预期存在：</p><ul><li><code>opencode.json</code></li><li><code>.agents/rules/</code></li><li><code>.agents/skills/</code></li></ul><p>可以在 settings 中重新生成 agent config。如果你曾从 Claude Code 切换过来，请确认当前 active platform 是 OpenCode。</p><h2 id="broken-wikilinks" tabindex="-1">Broken Wikilinks <a class="header-anchor" href="#broken-wikilinks" aria-label="Permalink to “Broken Wikilinks”">​</a></h2><p>Broken wikilinks 表示 Obsidian 无法解析链接目标。</p><p>常见原因：</p><ul><li>目标 note 被重命名或删除。</li><li>link text 有拼写错误。</li><li>note 存在于其他 folder，但标题和预期不同。</li></ul><p>修复 link 或恢复目标 note，然后再次运行 diagnosis。</p><h2 id="orphan-notes" tabindex="-1">Orphan Notes <a class="header-anchor" href="#orphan-notes" aria-label="Permalink to “Orphan Notes”">​</a></h2><p>Orphan notes 是没有 incoming wikilinks 的笔记。</p><p>这不一定是坏事。Daily notes、inbox notes 或临时 notes 可能本来就是孤立的。对于 knowledge pages 来说，orphan 通常意味着页面尚未接回知识地图。</p><h2 id="missing-frontmatter" tabindex="-1">Missing Frontmatter <a class="header-anchor" href="#missing-frontmatter" aria-label="Permalink to “Missing Frontmatter”">​</a></h2><p>Knowlery 只检查知识目录中的 frontmatter。</p><p>如果 <code>entities/</code>、<code>concepts/</code>、<code>comparisons/</code> 或 <code>queries/</code> 中的文件缺少 frontmatter，请对照 <code>SCHEMA.md</code> 添加缺失字段。</p><h2 id="optional-installs-失败" tabindex="-1">Optional Installs 失败 <a class="header-anchor" href="#optional-installs-失败" aria-label="Permalink to “Optional Installs 失败”">​</a></h2><p>Optional installs 会在你的机器上运行本地命令。</p><p>如果安装失败：</p><ol><li>检查该项目需要 Node 时，Node.js 是否已检测到。</li><li>在 terminal 中尝试等价安装命令。</li><li>安装外部工具后重启 Obsidian。</li><li>重新打开 setup 或 settings，再次运行 detection。</li></ol><h2 id="knowledge-bundle-无法安装" tabindex="-1">Knowledge Bundle 无法安装 <a class="header-anchor" href="#knowledge-bundle-无法安装" aria-label="Permalink to “Knowledge Bundle 无法安装”">​</a></h2><p>安装前会先校验 bundle，任何校验失败都不会写入内容。</p><p>常见原因：</p><ul><li><code>.zip</code> 或文件夹的根目录下没有 <code>knowlery-bundle.json</code> manifest。</li><li>Bundle id 不是路径安全的，或某个条目路径试图逃出 <code>Library/&lt;bundle-id&gt;/</code>。</li><li>相同 bundle 已经以相同或更新的版本安装——更新要求更高的 bundle 版本号。</li><li>Bundle 存在 conformance 错误——需要在安装预览中显式确认才能继续。</li></ul><p>如果 manifest 或路径有问题，请让分享者用当前版本的 Knowlery 重新导出。</p><h2 id="已安装-bundle-的知识没有出现在回答里" tabindex="-1">已安装 Bundle 的知识没有出现在回答里 <a class="header-anchor" href="#已安装-bundle-的知识没有出现在回答里" aria-label="Permalink to “已安装 Bundle 的知识没有出现在回答里”">​</a></h2><p><code>/ask</code> skill 会读取 <code>.knowlery/bundles.json</code>，以及 <code>Library/&lt;bundle-id&gt;/</code> 下每个相关 bundle 的 <code>agent-index.json</code>。</p><p>依次检查：</p><ol><li>Bundle 出现在 dashboard 的 Bundles 区块中。</li><li><code>.knowlery/bundles.json</code> 里登记了这个 bundle。</li><li><code>KNOWLEDGE.md</code> 中存在 installed-bundles 指引块。</li><li>Vault 里的 <code>/ask</code> skill 是最新的——插件版本变化时 bundled skills 会自动刷新。</li></ol><h2 id="什么时候提交-issue" tabindex="-1">什么时候提交 Issue <a class="header-anchor" href="#什么时候提交-issue" aria-label="Permalink to “什么时候提交 Issue”">​</a></h2><p>当你能在 clean test vault 中稳定复现问题时，可以提交 GitHub issue，并附上：</p><ul><li>Knowlery version。</li><li>Obsidian version。</li><li>操作系统。</li><li>Active platform，是 Claude Code 还是 OpenCode。</li><li>复现步骤。</li><li>相关 console errors。</li></ul>',56)])])}const k=l(n,[["render",s]]);export{u as __pageData,k as default};
